import json, re, unicodedata, pathlib
base=pathlib.Path('/mnt/data/euro-champions-draft')

def slug(s):
    s=unicodedata.normalize('NFKD',s).encode('ascii','ignore').decode().lower()
    return re.sub(r'[^a-z0-9]+','_',s).strip('_')

def P(name,pos,rating,traits=None):
    return dict(name=name,positions=pos if isinstance(pos,list) else [pos],rating=rating,traits=traits or [])

