seasons=[]; players=[]
for sid,club,season,result,theme,plist in raw:
    seasons.append(dict(id=sid,club=club,season=season,result=result,theme=theme))
    for p in plist:
        d={
          'id': f"{sid}_{slug(p['name'])}",
          'name':p['name'],'club':club,'season':season,'seasonId':sid,
          'positions':p['positions'],'rating':p['rating'],'traits':p['traits']}
        players.append(d)
# de-dupe in same id? add suffix if necessary
seen={}
for p in players:
    if p['id'] in seen:
        seen[p['id']]+=1; p['id']=p['id']+'_'+str(seen[p['id']])
    else: seen[p['id']]=1
(base/'src/data/seasons.js').write_text('export const seasons = '+json.dumps(seasons,ensure_ascii=False,indent=2)+';\n')
(base/'src/data/players.js').write_text('export const players = '+json.dumps(players,ensure_ascii=False,indent=2)+';\n')
print(len(seasons),len(players))
